import{_ as e,o,c as r,a2 as n}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Agent Streaming Comparison","description":"","frontmatter":{},"headers":[],"relativePath":"research/concepts/streaming/agent-comparison.md","filePath":"research/concepts/streaming/agent-comparison.md"}'),i={name:"research/concepts/streaming/agent-comparison.md"};function d(a,t,s,l,c,p){return o(),r("div",null,[...t[0]||(t[0]=[n(`<h1 id="agent-streaming-comparison" tabindex="-1">Agent Streaming Comparison <a class="header-anchor" href="#agent-streaming-comparison" aria-label="Permalink to &quot;Agent Streaming Comparison&quot;">​</a></h1><p>Comprehensive cross-agent comparison of streaming implementations across the major open-source and commercial coding agents. This document examines protocol choices, TUI frameworks, parsing strategies, rendering pipelines, error recovery mechanisms, and architectural patterns that define how each agent handles real-time LLM output.</p><hr><h2 id="_1-protocol-comparison" tabindex="-1">1. Protocol Comparison <a class="header-anchor" href="#_1-protocol-comparison" aria-label="Permalink to &quot;1. Protocol Comparison&quot;">​</a></h2><p>How each agent receives streamed tokens from LLM providers.</p><table tabindex="0"><thead><tr><th>Agent</th><th>Primary Protocol</th><th>Transport Layer</th><th>Bidirectional?</th><th>Notes</th></tr></thead><tbody><tr><td><strong>OpenCode</strong></td><td>SSE</td><td>Go HTTP client → channels</td><td>No</td><td>Provider layer emits unified ProviderEvent types</td></tr><tr><td><strong>Claude Code</strong></td><td>SSE</td><td>Anthropic Messages API</td><td>No</td><td>Content block streaming with start/delta/stop lifecycle</td></tr><tr><td><strong>Codex</strong></td><td>SSE + WebSocket</td><td>Responses API</td><td>Yes (realtime)</td><td>Only supports OpenAI Responses API; WebSocket for realtime mode</td></tr><tr><td><strong>Gemini CLI</strong></td><td>SSE</td><td>client.ts handler</td><td>No</td><td>Separate core and CLI packages; contentGenerator.ts bridges them</td></tr><tr><td><strong>Goose</strong></td><td>Async stream</td><td><code>BoxStream&lt;AgentEvent&gt;</code></td><td>No</td><td>Rust async streams yielding (Message, Usage) tuples</td></tr><tr><td><strong>Aider</strong></td><td>SSE (via litellm)</td><td>litellm abstraction</td><td>No</td><td>Provider-agnostic through litellm; supports 100+ providers</td></tr><tr><td><strong>Warp</strong></td><td>N/A (terminal-native)</td><td>PTY buffer</td><td>N/A</td><td>GPU-accelerated terminal, not an API client</td></tr><tr><td><strong>Pi Coding Agent</strong></td><td>Provider-specific</td><td>Event streaming</td><td>No</td><td>Extension-based providers with tool:start/tool:complete events</td></tr><tr><td><strong>OpenHands</strong></td><td>WebSocket/REST</td><td>EventStream</td><td>Yes</td><td>Append-only event bus with full replay capability</td></tr><tr><td><strong>Droid</strong></td><td>WebSocket</td><td>Interface-agnostic</td><td>Yes</td><td>Multi-frontend architecture (Slack, web, CLI)</td></tr><tr><td><strong>Ante</strong></td><td>HTTP streaming</td><td>Rust native</td><td>No</td><td>Lock-free scheduler for concurrent sub-agent streaming</td></tr><tr><td><strong>Junie CLI</strong></td><td>WebSocket/HTTP</td><td>JetBrains backend</td><td>Yes</td><td>Connects to JetBrains IDE backend for tool execution</td></tr><tr><td><strong>ForgeCode</strong></td><td>ZSH-native</td><td>Shell integration</td><td>N/A</td><td><code>:</code> prefix commands in ZSH; no separate streaming layer</td></tr><tr><td><strong>mini-SWE-agent</strong></td><td>None (no streaming)</td><td>subprocess.run</td><td>N/A</td><td>~350 lines total; synchronous request/response only</td></tr></tbody></table><h3 id="protocol-details" tabindex="-1">Protocol Details <a class="header-anchor" href="#protocol-details" aria-label="Permalink to &quot;Protocol Details&quot;">​</a></h3><ul><li><p><strong>SSE (Server-Sent Events)</strong>: The dominant protocol. Unidirectional server→client text stream over HTTP. Each event is a <code>data:</code> line followed by <code>\\n\\n</code>. Most providers (Anthropic, OpenAI completions, Google) support this natively.</p></li><li><p><strong>WebSocket</strong>: Used by Codex for OpenAI Realtime API and by OpenHands for its event-driven architecture. Enables bidirectional communication but adds complexity in reconnection and state management.</p></li><li><p><strong>Async Streams</strong>: Goose and Ante use Rust&#39;s native async streaming (<code>Stream</code> trait) rather than HTTP-level protocols. The provider adapter handles HTTP internally and exposes a typed async iterator.</p></li></ul><hr><h2 id="_2-tui-framework-comparison" tabindex="-1">2. TUI Framework Comparison <a class="header-anchor" href="#_2-tui-framework-comparison" aria-label="Permalink to &quot;2. TUI Framework Comparison&quot;">​</a></h2><p>The terminal user interface technology each agent uses for rendering streamed output.</p><table tabindex="0"><thead><tr><th>Agent</th><th>TUI Framework</th><th>Language</th><th>Rendering Model</th><th>Rich UI Level</th></tr></thead><tbody><tr><td><strong>Claude Code</strong></td><td>Ink (React)</td><td>TypeScript</td><td>Virtual DOM diff</td><td>High</td></tr><tr><td><strong>Gemini CLI</strong></td><td>Ink (React)</td><td>TypeScript</td><td>Virtual DOM diff</td><td>High</td></tr><tr><td><strong>OpenCode</strong></td><td>Bubble Tea</td><td>Go</td><td>Elm Architecture (MVU)</td><td>Medium-High</td></tr><tr><td><strong>Codex</strong></td><td>Ratatui</td><td>Rust</td><td>Immediate-mode widgets</td><td>Medium</td></tr><tr><td><strong>Warp</strong></td><td>Custom (Metal GPU)</td><td>Rust</td><td>Flutter-style element tree</td><td>Very High</td></tr><tr><td><strong>Pi Coding Agent</strong></td><td>Custom (pi-tui)</td><td>TypeScript</td><td>Differential rendering</td><td>High</td></tr><tr><td><strong>Aider</strong></td><td>prompt_toolkit</td><td>Python</td><td>Input/output library</td><td>Low-Medium</td></tr><tr><td><strong>Goose</strong></td><td>Event-driven UI</td><td>Rust</td><td>Progressive rendering</td><td>Medium</td></tr><tr><td><strong>OpenHands</strong></td><td>Web UI</td><td>TypeScript</td><td>React (browser)</td><td>Very High</td></tr><tr><td><strong>Droid</strong></td><td>Multi-frontend</td><td>Various</td><td>Interface-agnostic</td><td>Varies</td></tr><tr><td><strong>ForgeCode</strong></td><td>ZSH shell</td><td>Shell</td><td>No custom rendering</td><td>Minimal</td></tr><tr><td><strong>mini-SWE-agent</strong></td><td>None (raw print)</td><td>Python</td><td>print()</td><td>Minimal</td></tr></tbody></table><h3 id="framework-architecture-notes" tabindex="-1">Framework Architecture Notes <a class="header-anchor" href="#framework-architecture-notes" aria-label="Permalink to &quot;Framework Architecture Notes&quot;">​</a></h3><p><strong>Ink (React for CLI)</strong>: Claude Code and Gemini CLI both use Ink, which brings React&#39;s component model to the terminal. Components like <code>&lt;Box&gt;</code>, <code>&lt;Text&gt;</code>, and custom elements render via virtual DOM diffing. This enables complex layouts (permission dialogs, multi-pane views) but adds startup overhead (~200ms).</p><p><strong>Bubble Tea (Elm Architecture)</strong>: OpenCode uses the MVU pattern: Model holds state, Update processes messages, View renders. Messages arrive as <code>tea.Msg</code> from the streaming pub/sub system. Well-suited for Go&#39;s concurrency model.</p><p><strong>Ratatui (Immediate Mode)</strong>: Codex renders the entire frame each tick. Widgets describe what to draw; the framework handles diffing against the terminal buffer. Efficient for Rust&#39;s ownership model—no retained widget tree to manage.</p><p><strong>Metal GPU Rendering</strong>: Warp bypasses traditional terminal rendering entirely. Text is rendered via Metal shaders at ~1.9ms per frame. This enables true rich rendering: inline images, animated progress bars, multi-font layouts.</p><hr><h2 id="_3-streaming-parsing-comparison" tabindex="-1">3. Streaming Parsing Comparison <a class="header-anchor" href="#_3-streaming-parsing-comparison" aria-label="Permalink to &quot;3. Streaming Parsing Comparison&quot;">​</a></h2><p>How each agent parses incoming stream chunks into structured data.</p><table tabindex="0"><thead><tr><th>Agent</th><th>Parsing Strategy</th><th>Provider Normalization</th><th>JSON Assembly</th><th>Tool Call Handling</th></tr></thead><tbody><tr><td><strong>OpenCode</strong></td><td>Delta events → SQLite → pub/sub</td><td>ProviderEvent types (EventContentDelta, EventToolUseStart, etc.)</td><td>String accumulation, parse at EventComplete</td><td>Per-tool entry tracking by ID</td></tr><tr><td><strong>Claude Code</strong></td><td>Content block lifecycle</td><td>Anthropic-only (native format)</td><td>Buffer until content_block_stop</td><td>Anthropic block lifecycle events</td></tr><tr><td><strong>Codex</strong></td><td>Item lifecycle (Responses API)</td><td>OpenAI Responses API only</td><td>ItemCreated → ItemUpdated → ItemCompleted</td><td>ToolRouter.build_tool_call() dispatches</td></tr><tr><td><strong>Gemini CLI</strong></td><td>contentGenerator.ts pipeline</td><td>Gemini format normalization</td><td>Provider-specific parsing in core</td><td>Gemini function call format</td></tr><tr><td><strong>Goose</strong></td><td>Stream chunks → categorize_tools()</td><td>stream_response_from_provider() yields (Message, Usage)</td><td>Accumulate strings, coerce types</td><td>categorize_tools() splits frontend/backend</td></tr><tr><td><strong>Aider</strong></td><td>Edit format parsers</td><td>litellm normalizes to OpenAI format</td><td>litellm handles JSON assembly</td><td>Edit format routing (diff/whole/udiff)</td></tr><tr><td><strong>Pi</strong></td><td>Event streaming API</td><td>Extension-based providers</td><td>Provider-specific in extensions</td><td>tool:start, tool:complete lifecycle events</td></tr><tr><td><strong>Ante</strong></td><td>fn stream() → TokenStream</td><td>HTTP streaming in Rust</td><td>Rust native serde parsing</td><td>Lock-free per-sub-agent dispatch</td></tr></tbody></table><h3 id="parsing-deep-dive" tabindex="-1">Parsing Deep Dive <a class="header-anchor" href="#parsing-deep-dive" aria-label="Permalink to &quot;Parsing Deep Dive&quot;">​</a></h3><p><strong>Delta Accumulation</strong>: Most agents accumulate text deltas into a growing string buffer. The critical question is when to parse. OpenCode parses tool call JSON only at <code>EventComplete</code>, avoiding partial-JSON errors. Codex uses <code>ItemCompleted</code> similarly.</p><p><strong>Tool Call JSON Assembly</strong>: Tool calls arrive as partial JSON fragments across multiple SSE events. Example sequence:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>data: {&quot;type&quot;:&quot;tool_use&quot;,&quot;id&quot;:&quot;tool_1&quot;,&quot;name&quot;:&quot;read_file&quot;,&quot;input&quot;:&quot;&quot;}</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;input_json_delta&quot;,&quot;partial_json&quot;:&quot;{\\&quot;path\\&quot;:&quot;}</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;input_json_delta&quot;,&quot;partial_json&quot;:&quot;\\&quot;src/main.rs\\&quot;&quot;}</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;input_json_delta&quot;,&quot;partial_json&quot;:&quot;}&quot;}</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;tool_use_stop&quot;}</span></span></code></pre></div><p>Agents must accumulate these fragments and parse the complete JSON only after the stop event. Premature parsing causes <code>SyntaxError</code> on partial JSON.</p><p><strong>Type Coercion</strong> (Goose): When a tool schema expects <code>integer</code> but the LLM produces <code>&quot;42&quot;</code> (string), Goose&#39;s argument coercion layer automatically converts. This handles a common LLM failure mode where numbers are quoted.</p><hr><h2 id="_4-rendering-approach-comparison" tabindex="-1">4. Rendering Approach Comparison <a class="header-anchor" href="#_4-rendering-approach-comparison" aria-label="Permalink to &quot;4. Rendering Approach Comparison&quot;">​</a></h2><p>How streamed tokens become visible output in the user&#39;s terminal.</p><table tabindex="0"><thead><tr><th>Agent</th><th>Markdown Rendering</th><th>Syntax Highlighting</th><th>Diff Display</th><th>Progress Indicators</th></tr></thead><tbody><tr><td><strong>Claude Code</strong></td><td>Ink component pipeline</td><td>Within Ink components</td><td>Colored inline diffs</td><td>Custom spinner verbs, iTerm2 progress bar</td></tr><tr><td><strong>OpenCode</strong></td><td>Lip Gloss styled</td><td>Via Bubble Tea components</td><td>Styled diff view with line numbers</td><td>Spinner + format utilities</td></tr><tr><td><strong>Codex</strong></td><td>Ratatui widgets</td><td>Within TUI cells</td><td>TUI-based side-by-side diff</td><td>Turn lifecycle events as status</td></tr><tr><td><strong>Gemini CLI</strong></td><td>Ink components</td><td>Ink component tree</td><td>Component-based diff rendering</td><td>Standard Ink spinner patterns</td></tr><tr><td><strong>Warp</strong></td><td>GPU-rendered multi-font</td><td>GPU syntax highlighting shaders</td><td>Rich diff views with color blending</td><td>GPU-animated progress bars</td></tr><tr><td><strong>Aider</strong></td><td>Full markdown via Rich/io.py</td><td>Color-coded terminal output</td><td>Git-based diff display (unified)</td><td>prompt_toolkit bottom toolbar</td></tr><tr><td><strong>Goose</strong></td><td>Event-driven progressive</td><td>Provider-dependent rendering</td><td>Event-based diff display</td><td>CancellationToken-based spinners</td></tr><tr><td><strong>Pi</strong></td><td>Custom pi-tui differential</td><td>Extension-dependent</td><td>Component-based diff views</td><td>Extension event progress indicators</td></tr><tr><td><strong>OpenHands</strong></td><td>Web React components</td><td>Monaco editor highlighting</td><td>Web diff viewer (side-by-side)</td><td>Event-driven web progress bars</td></tr></tbody></table><h3 id="rendering-pipeline-details" tabindex="-1">Rendering Pipeline Details <a class="header-anchor" href="#rendering-pipeline-details" aria-label="Permalink to &quot;Rendering Pipeline Details&quot;">​</a></h3><p><strong>Claude Code Pipeline</strong>:</p><ol><li>SSE event arrives → content block delta</li><li>Text accumulated in conversation state</li><li>React (Ink) component re-renders with new text</li><li>Ink diffs virtual DOM → minimal terminal escape sequences</li><li>Markdown parsed inline; code blocks get syntax highlighting</li></ol><p><strong>OpenCode Pipeline</strong>:</p><ol><li>Provider emits <code>EventContentDelta</code></li><li>Persisted to SQLite row</li><li><code>Broker[T]</code> publishes to subscribers</li><li>Bubble Tea model receives <code>tea.Msg</code></li><li>View function renders with Lip Gloss styling</li><li>Catppuccin theme applied to code blocks</li></ol><p><strong>Warp Pipeline</strong>:</p><ol><li>PTY output captured in Block grid buffer</li><li>Element tree updated (Flutter-style layout)</li><li>Metal shader compiles glyph atlases</li><li>GPU renders at ~1.9ms including syntax highlighting</li><li>Inline images, buttons rendered as GPU textures</li></ol><hr><h2 id="_5-error-recovery-comparison" tabindex="-1">5. Error Recovery Comparison <a class="header-anchor" href="#_5-error-recovery-comparison" aria-label="Permalink to &quot;5. Error Recovery Comparison&quot;">​</a></h2><p>How each agent handles failures during streaming.</p><table tabindex="0"><thead><tr><th>Agent</th><th>Max Retries</th><th>Reconnection</th><th>Partial Response</th><th>Rate Limit</th><th>User Interrupt</th><th>Unique Feature</th></tr></thead><tbody><tr><td><strong>Codex</strong></td><td>5 (stream) / 4 (request)</td><td>Retry from scratch</td><td>Discard + retry</td><td>Provider-level 429 handling</td><td>Op::Interrupt → TurnAborted</td><td>300s idle timeout auto-abort</td></tr><tr><td><strong>OpenCode</strong></td><td>8</td><td>Retry from scratch</td><td>Persist to SQLite (even partial)</td><td>Provider layer handles</td><td>Context cancellation cascade</td><td>4-level cancellation hierarchy</td></tr><tr><td><strong>Claude Code</strong></td><td>Provider SDK default</td><td>Provider SDK retry logic</td><td>Checkpoint snapshots preserved</td><td>SDK handles transparently</td><td>Esc preserves context</td><td>File snapshot rewind menu</td></tr><tr><td><strong>Goose</strong></td><td>2 (compaction)</td><td>Break + preserve state</td><td>Emergency compaction triggers</td><td>CreditsExhausted with top_up_url</td><td>CancellationToken propagation</td><td>compact_messages() for overflow</td></tr><tr><td><strong>Gemini CLI</strong></td><td>Configurable</td><td>Retry + fallback module</td><td>Discard + retry fresh</td><td>Fallback to alternative model</td><td>Standard Ink interrupt</td><td>Fallback model routing</td></tr><tr><td><strong>Aider</strong></td><td>Via litellm defaults</td><td>litellm handles reconnection</td><td>Discard + retry</td><td>litellm transparent retry</td><td>Standard SIGINT</td><td>Git-based undo for edits</td></tr><tr><td><strong>OpenHands</strong></td><td>Event replay</td><td>EventStream persistent</td><td>Full state reconstruction</td><td>Backend handles</td><td>Web UI cancel button</td><td>ReplayManager for recovery</td></tr><tr><td><strong>Ante</strong></td><td>Sub-agent isolation</td><td>Per sub-agent retry</td><td>Sub-agents independent</td><td>Per sub-agent limits</td><td>Lock-free scheduler abort</td><td>Sub-agent fault isolation</td></tr><tr><td><strong>Pi</strong></td><td>Extension-based</td><td>Extension handles retry</td><td>Extension-dependent</td><td>Extension handles</td><td>Enter = steer, not cancel</td><td>Mid-stream steering</td></tr></tbody></table><h3 id="error-recovery-deep-dive" tabindex="-1">Error Recovery Deep Dive <a class="header-anchor" href="#error-recovery-deep-dive" aria-label="Permalink to &quot;Error Recovery Deep Dive&quot;">​</a></h3><p><strong>OpenCode&#39;s 4-Level Cancellation</strong>:</p><ol><li><strong>Session level</strong>: Cancels everything, closes session</li><li><strong>Loop level</strong>: Cancels current agent loop iteration</li><li><strong>Stream level</strong>: Cancels active SSE connection, preserves loop</li><li><strong>Tool level</strong>: Cancels running tool execution only</li></ol><p>Each level has its own <code>context.Context</code> with proper parent-child relationships. Cancelling a parent automatically cancels all children.</p><p><strong>Claude Code&#39;s File Snapshots</strong>: Before every file edit, Claude Code captures a snapshot. If the user presses Esc twice, they get a menu to rewind any or all file changes. This is a coarse-grained but highly reliable recovery mechanism.</p><p><strong>Goose&#39;s Emergency Compaction</strong>: When context exceeds the model&#39;s window, Goose triggers <code>compact_messages()</code>. This summarizes the conversation history into a shorter form, preserving critical context while freeing token budget. Limited to 2 retries before surfacing the error to the user.</p><p><strong>Codex&#39;s Idle Timeout</strong>: If the LLM stops producing tokens for 300 seconds, Codex automatically aborts the turn. This prevents hung connections from blocking the user indefinitely. The <code>Op::Interrupt</code> signal cleanly transitions to <code>TurnAborted</code>.</p><hr><h2 id="_6-detailed-agent-profiles" tabindex="-1">6. Detailed Agent Profiles <a class="header-anchor" href="#_6-detailed-agent-profiles" aria-label="Permalink to &quot;6. Detailed Agent Profiles&quot;">​</a></h2><h3 id="opencode-go" tabindex="-1">OpenCode (Go) <a class="header-anchor" href="#opencode-go" aria-label="Permalink to &quot;OpenCode (Go)&quot;">​</a></h3><ul><li><strong>Protocol</strong>: SSE via Go HTTP client with goroutine-per-stream</li><li><strong>Parsing</strong>: Provider layer emits unified <code>ProviderEvent</code> types regardless of upstream <ul><li><code>EventContentDelta</code> — text token arrived</li><li><code>EventToolUseStart</code> — tool call begins (includes name, ID)</li><li><code>EventToolUseStop</code> — tool call JSON complete</li><li><code>EventThinkingDelta</code> — reasoning/thinking token</li><li><code>EventComplete</code> — stream finished, includes usage stats</li></ul></li><li><strong>State</strong>: Every delta persisted to SQLite immediately via <code>store</code> package</li><li><strong>Pub/Sub</strong>: Generic typed <code>Broker[T]</code> system publishes events to multiple subscribers</li><li><strong>TUI</strong>: Bubble Tea receives events as <code>tea.Msg</code> via subscription</li><li><strong>Rendering</strong>: Lip Gloss styling with Catppuccin Mocha/Latte themes</li><li><strong>Images</strong>: Inline image rendering via Kitty/iTerm2 protocols</li><li><strong>Error Recovery</strong>: 8 retries with exponential backoff; 4-level context cancellation</li></ul><h3 id="claude-code-typescript" tabindex="-1">Claude Code (TypeScript) <a class="header-anchor" href="#claude-code-typescript" aria-label="Permalink to &quot;Claude Code (TypeScript)&quot;">​</a></h3><ul><li><strong>Protocol</strong>: SSE via Anthropic Messages API (<code>@anthropic-ai/sdk</code>)</li><li><strong>Parsing</strong>: Content block start → delta → stop lifecycle <ul><li><code>content_block_start</code> — new text or tool_use block</li><li><code>content_block_delta</code> — incremental text or JSON fragment</li><li><code>content_block_stop</code> — block complete</li><li><code>message_stop</code> — entire message complete</li></ul></li><li><strong>State</strong>: Conversation state held in-memory; file snapshots on disk</li><li><strong>TUI</strong>: Full Ink (React) application with JSX components</li><li><strong>Rendering</strong>: Rich component tree: diffs, spinners, permission dialogs, markdown</li><li><strong>Thinking</strong>: Extended thinking blocks toggleable with Ctrl+O</li><li><strong>Error Recovery</strong>: File snapshots before edits; Esc+Esc for rewind menu</li><li><strong>Unique</strong>: Multi-turn tool use with automatic permission escalation</li></ul><h3 id="codex-rust" tabindex="-1">Codex (Rust) <a class="header-anchor" href="#codex-rust" aria-label="Permalink to &quot;Codex (Rust)&quot;">​</a></h3><ul><li><strong>Protocol</strong>: SSE + WebSocket via OpenAI Responses API exclusively</li><li><strong>Parsing</strong>: Item-based lifecycle <ul><li><code>ItemCreated</code> — new response item (text, tool call, etc.)</li><li><code>ItemUpdated</code> — delta for existing item</li><li><code>ItemCompleted</code> — item fully received</li></ul></li><li><strong>Architecture</strong>: SQ (Submission Queue) / EQ (Event Queue) separation <ul><li>SQ: User and system submit operations</li><li>EQ: Events flow back (turn updates, tool results)</li></ul></li><li><strong>TUI</strong>: Ratatui (one of multiple frontends)</li><li><strong>Other Frontends</strong>: exec mode (JSONL stdout), app-server (IDE integration), MCP server</li><li><strong>Tool Routing</strong>: <code>ToolRouter</code> maps items to MCP servers, built-in handlers, local shell</li><li><strong>Error Recovery</strong>: 5 stream retries, 4 request retries, 300s idle timeout</li><li><strong>Unique</strong>: <code>Op::Interrupt</code> signal for clean abort mid-stream</li></ul><h3 id="goose-rust" tabindex="-1">Goose (Rust) <a class="header-anchor" href="#goose-rust" aria-label="Permalink to &quot;Goose (Rust)&quot;">​</a></h3><ul><li><strong>Protocol</strong>: Async <code>BoxStream&lt;AgentEvent&gt;</code> from provider adapters</li><li><strong>Parsing</strong>: <code>stream_response_from_provider()</code> yields <code>(Option&lt;Message&gt;, Option&lt;ProviderUsage&gt;)</code></li><li><strong>Tool Routing</strong>: <code>categorize_tools()</code> splits tools into: <ul><li><strong>Frontend tools</strong>: UI-facing (display, prompt user)</li><li><strong>Backend tools</strong>: System-facing (file ops, shell commands)</li></ul></li><li><strong>Argument Coercion</strong>: Converts <code>&quot;42&quot;</code> string to <code>42</code> number when schema expects integer</li><li><strong>Context Management</strong>: <code>compact_messages()</code> for emergency context window overflow</li><li><strong>Error Recovery</strong>: CancellationToken propagation, CreditsExhausted with <code>top_up_url</code></li><li><strong>Unique</strong>: Built-in <code>platform</code> tool for cross-platform system interaction</li></ul><h3 id="gemini-cli-typescript" tabindex="-1">Gemini CLI (TypeScript) <a class="header-anchor" href="#gemini-cli-typescript" aria-label="Permalink to &quot;Gemini CLI (TypeScript)&quot;">​</a></h3><ul><li><strong>Architecture</strong>: Monorepo with <code>packages/core/</code> (UI-agnostic) and <code>packages/cli/</code> (Ink UI)</li><li><strong>Parsing</strong>: <code>contentGenerator.ts</code> bridges the agent loop and LLM client</li><li><strong>Headless Modes</strong>: Three output formats for non-interactive use: <ul><li><code>text</code> — human-readable plain text</li><li><code>json</code> — structured JSON output</li><li><code>stream-json</code> — newline-delimited JSON (NDJSON) for piping</li></ul></li><li><strong>Model Fallback</strong>: Retry logic with fallback module for routing to alternative models</li><li><strong>Error Recovery</strong>: Configurable retry count; automatic model fallback on failure</li><li><strong>Unique</strong>: First-party Google integration with Gemini-specific optimizations</li></ul><h3 id="aider-python" tabindex="-1">Aider (Python) <a class="header-anchor" href="#aider-python" aria-label="Permalink to &quot;Aider (Python)&quot;">​</a></h3><ul><li><strong>Protocol</strong>: litellm normalizes SSE across 100+ LLM providers</li><li><strong>Parsing</strong>: Edit format parsers handle multiple output styles: <ul><li><code>EditBlockCoder</code> — search/replace blocks</li><li><code>WholeFileCoder</code> — complete file replacement</li><li><code>UnifiedDiffCoder</code> — unified diff format</li><li><code>ArchitectCoder</code> — two-model pipeline (architect + editor)</li></ul></li><li><strong>TUI</strong>: prompt_toolkit for rich input; Rich library for formatted output</li><li><strong>Voice Input</strong>: <code>--voice</code> flag activates OpenAI Whisper for speech-to-code</li><li><strong>Model Detection</strong>: Automatically detects reasoning models → routes to ArchitectCoder</li><li><strong>Error Recovery</strong>: Git-based undo; every edit creates a commit for easy revert</li><li><strong>Unique</strong>: Repository map via tree-sitter for intelligent context selection</li></ul><h3 id="warp-rust-metal" tabindex="-1">Warp (Rust + Metal) <a class="header-anchor" href="#warp-rust-metal" aria-label="Permalink to &quot;Warp (Rust + Metal)&quot;">​</a></h3><ul><li><strong>Architecture</strong>: GPU-accelerated terminal application (not an LLM API client)</li><li><strong>Rendering</strong>: Metal shaders render text at ~1.9ms per frame <ul><li>Glyph atlas caching for font rendering</li><li>Multi-font support within single view</li><li>Flutter-inspired element tree for layout</li></ul></li><li><strong>Block Model</strong>: Each command + output is a discrete <code>Block</code> with its own grid <ul><li>Blocks are individually selectable, copyable, shareable</li><li>AI can analyze individual block output</li></ul></li><li><strong>AI Features</strong>: <ul><li>Proactive error detection on command failure</li><li>Natural language → command translation</li><li>Conversation view for multi-turn interaction</li></ul></li><li><strong>Unique</strong>: Only agent that renders via GPU; diffs, progress bars, buttons all GPU-rendered</li></ul><h3 id="openhands-typescript-python" tabindex="-1">OpenHands (TypeScript + Python) <a class="header-anchor" href="#openhands-typescript-python" aria-label="Permalink to &quot;OpenHands (TypeScript + Python)&quot;">​</a></h3><ul><li><strong>Architecture</strong>: Full-stack web application with event-driven backend</li><li><strong>Protocol</strong>: WebSocket for real-time events; REST for state queries</li><li><strong>EventStream</strong>: Append-only event bus — the core abstraction <ul><li>All actions and observations are events</li><li>Events are immutable once appended</li><li>Full replay from any point via <code>ReplayManager</code></li></ul></li><li><strong>State</strong>: Complete state reconstructible from event log</li><li><strong>UI</strong>: React web application with Monaco editor integration</li><li><strong>Error Recovery</strong>: Full state reconstruction from event replay</li><li><strong>Unique</strong>: Most robust recovery model; can resume from any failure point</li></ul><h3 id="pi-coding-agent-typescript" tabindex="-1">Pi Coding Agent (TypeScript) <a class="header-anchor" href="#pi-coding-agent-typescript" aria-label="Permalink to &quot;Pi Coding Agent (TypeScript)&quot;">​</a></h3><ul><li><strong>Architecture</strong>: Extension-based with <code>pi-tui</code> custom terminal UI</li><li><strong>Providers</strong>: Implemented as extensions, each with own streaming protocol</li><li><strong>Tool Lifecycle</strong>: <code>tool:start</code> → progress events → <code>tool:complete</code></li><li><strong>Rendering</strong>: Differential rendering — only updates changed terminal regions</li><li><strong>Interrupt Model</strong>: Enter key steers the agent mid-stream rather than cancelling</li><li><strong>Unique</strong>: Mid-stream steering lets users redirect without losing context</li></ul><hr><h2 id="_7-key-architectural-patterns" tabindex="-1">7. Key Architectural Patterns <a class="header-anchor" href="#_7-key-architectural-patterns" aria-label="Permalink to &quot;7. Key Architectural Patterns&quot;">​</a></h2><h3 id="provider-normalization-spectrum" tabindex="-1">Provider Normalization Spectrum <a class="header-anchor" href="#provider-normalization-spectrum" aria-label="Permalink to &quot;Provider Normalization Spectrum&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Full Normalization          Partial Normalization          Single Provider</span></span>
<span class="line"><span>     │                            │                             │</span></span>
<span class="line"><span>  OpenCode                     Goose                      Claude Code</span></span>
<span class="line"><span>  Aider/litellm             Gemini CLI                      Codex</span></span>
<span class="line"><span>                                Pi</span></span></code></pre></div><ul><li><p><strong>Full normalization</strong> (OpenCode, Aider/litellm): All providers emit identical event types. Adding a new provider requires only implementing the adapter interface. Consumer code is completely provider-agnostic.</p></li><li><p><strong>Partial normalization</strong> (Goose, Gemini CLI): Stream handler abstracts away most provider differences, but some provider-specific behavior leaks through. Adding providers requires moderate effort.</p></li><li><p><strong>Single provider</strong> (Codex, Claude Code): Tightly coupled to one API format. No normalization layer exists. Maximum optimization for that provider&#39;s features, but zero portability.</p></li></ul><h3 id="state-management-during-streaming" tabindex="-1">State Management During Streaming <a class="header-anchor" href="#state-management-during-streaming" aria-label="Permalink to &quot;State Management During Streaming&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Strategy</th><th>Agent(s)</th><th>Durability</th><th>Recovery</th><th>Performance</th></tr></thead><tbody><tr><td>SQLite persistence</td><td>OpenCode</td><td>Survives crashes</td><td>Full replay</td><td>~1ms write overhead</td></tr><tr><td>In-memory</td><td>Claude Code, Codex</td><td>Lost on crash</td><td>None (restart)</td><td>Zero overhead</td></tr><tr><td>Append-only event log</td><td>OpenHands</td><td>Survives crashes</td><td>Full replay</td><td>Append-only writes</td></tr><tr><td>Checkpoint files</td><td>Claude Code</td><td>File-level snapshots</td><td>Rewind to checkpoint</td><td>File I/O per edit</td></tr><tr><td>Git commits</td><td>Aider</td><td>Full history</td><td>Git revert</td><td>Git overhead per edit</td></tr></tbody></table><h3 id="tool-call-architecture-patterns" tabindex="-1">Tool Call Architecture Patterns <a class="header-anchor" href="#tool-call-architecture-patterns" aria-label="Permalink to &quot;Tool Call Architecture Patterns&quot;">​</a></h3><ul><li><p><strong>Inline execution</strong> (most agents): Tool calls execute immediately as they complete during the stream. Simple but can block the stream if tool execution is slow.</p></li><li><p><strong>Categorized dispatch</strong> (Goose): <code>categorize_tools()</code> routes to frontend (UI) or backend (system) handlers. Frontend tools can update the UI while backend tools execute silently.</p></li><li><p><strong>Queued execution</strong> (Codex): SQ/EQ model separates submission from execution. Operations are queued and processed in order, enabling clean cancellation and prioritization.</p></li><li><p><strong>Extension-based</strong> (Pi): Tools implemented as extensions with their own streaming event lifecycle. Each extension manages its own state and error handling.</p></li><li><p><strong>Lock-free scheduling</strong> (Ante): Sub-agents run concurrently with lock-free coordination. Each sub-agent has independent streaming and tool execution.</p></li></ul><h3 id="cancellation-patterns" tabindex="-1">Cancellation Patterns <a class="header-anchor" href="#cancellation-patterns" aria-label="Permalink to &quot;Cancellation Patterns&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Simple SIGINT              Structured Cancellation         Event-Driven</span></span>
<span class="line"><span>     │                            │                             │</span></span>
<span class="line"><span>   Aider                      OpenCode                     OpenHands</span></span>
<span class="line"><span>  ForgeCode                     Codex                        Goose</span></span>
<span class="line"><span> mini-SWE-agent              Claude Code                      Pi</span></span></code></pre></div><ul><li><strong>Simple SIGINT</strong>: Standard Unix signal handling. Process stops; state may be lost.</li><li><strong>Structured</strong>: Hierarchical cancellation with context propagation. Parent cancels children.</li><li><strong>Event-Driven</strong>: Cancellation is itself an event in the stream. Observers react accordingly.</li></ul><hr><h2 id="_8-summary-matrix" tabindex="-1">8. Summary Matrix <a class="header-anchor" href="#_8-summary-matrix" aria-label="Permalink to &quot;8. Summary Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agent</th><th>Language</th><th>Protocol</th><th>TUI</th><th>Provider Support</th><th>State Persistence</th><th>Error Recovery</th><th>Complexity</th></tr></thead><tbody><tr><td><strong>OpenCode</strong></td><td>Go</td><td>SSE</td><td>Bubble Tea</td><td>Multi (normalized)</td><td>SQLite</td><td>8 retries, 4-level cancel</td><td>High</td></tr><tr><td><strong>Claude Code</strong></td><td>TypeScript</td><td>SSE</td><td>Ink (React)</td><td>Anthropic only</td><td>Memory + snapshots</td><td>SDK retry + file rewind</td><td>High</td></tr><tr><td><strong>Codex</strong></td><td>Rust</td><td>SSE+WS</td><td>Ratatui</td><td>OpenAI only</td><td>Memory</td><td>5+4 retries, idle timeout</td><td>Very High</td></tr><tr><td><strong>Gemini CLI</strong></td><td>TypeScript</td><td>SSE</td><td>Ink (React)</td><td>Google only</td><td>Memory</td><td>Retry + model fallback</td><td>Medium</td></tr><tr><td><strong>Goose</strong></td><td>Rust</td><td>Async stream</td><td>Event UI</td><td>Multi (partial)</td><td>Memory</td><td>Cancel token + compaction</td><td>High</td></tr><tr><td><strong>Aider</strong></td><td>Python</td><td>SSE/litellm</td><td>prompt_toolkit</td><td>100+ via litellm</td><td>Git commits</td><td>litellm retry + git undo</td><td>Medium</td></tr><tr><td><strong>Warp</strong></td><td>Rust</td><td>PTY</td><td>Metal GPU</td><td>N/A (terminal)</td><td>Block grid</td><td>N/A</td><td>Very High</td></tr><tr><td><strong>Pi</strong></td><td>TypeScript</td><td>Extension</td><td>pi-tui</td><td>Extension-based</td><td>Extension-based</td><td>Extension-based</td><td>Medium</td></tr><tr><td><strong>OpenHands</strong></td><td>TS+Python</td><td>WebSocket</td><td>Web React</td><td>Multi</td><td>Event log</td><td>Full replay</td><td>Very High</td></tr><tr><td><strong>Droid</strong></td><td>Various</td><td>WebSocket</td><td>Multi-frontend</td><td>Multi</td><td>Interface-dependent</td><td>Interface-dependent</td><td>High</td></tr><tr><td><strong>Ante</strong></td><td>Rust</td><td>HTTP stream</td><td>Minimal</td><td>Multi</td><td>Sub-agent scoped</td><td>Sub-agent isolation</td><td>Medium</td></tr><tr><td><strong>ForgeCode</strong></td><td>Shell</td><td>ZSH native</td><td>ZSH</td><td>Shell-based</td><td>None</td><td>None</td><td>Low</td></tr><tr><td><strong>mini-SWE-agent</strong></td><td>Python</td><td>None</td><td>None</td><td>Single</td><td>None</td><td>None</td><td>Minimal</td></tr></tbody></table><hr><h2 id="_9-key-takeaways" tabindex="-1">9. Key Takeaways <a class="header-anchor" href="#_9-key-takeaways" aria-label="Permalink to &quot;9. Key Takeaways&quot;">​</a></h2><ol><li><p><strong>SSE dominates</strong>: Nearly every agent uses Server-Sent Events as the primary streaming protocol. WebSocket is used only when bidirectional communication is essential (OpenHands, Codex realtime mode).</p></li><li><p><strong>Ink (React) is the most popular TUI</strong>: Claude Code and Gemini CLI both chose Ink, suggesting the React component model maps well to complex terminal UIs.</p></li><li><p><strong>Provider normalization is a spectrum</strong>: Agents that support multiple providers (OpenCode, Aider) invest heavily in normalization layers. Single-provider agents (Claude Code, Codex) skip this entirely for tighter integration.</p></li><li><p><strong>Error recovery correlates with complexity</strong>: The most sophisticated agents (OpenCode, Codex, OpenHands) have the most elaborate recovery mechanisms. Simpler agents rely on external tools (git, litellm) for recovery.</p></li><li><p><strong>State persistence varies wildly</strong>: From SQLite (OpenCode) to append-only logs (OpenHands) to nothing at all (mini-SWE-agent). The choice reflects each agent&#39;s reliability requirements.</p></li><li><p><strong>Tool call handling is the hardest streaming problem</strong>: Assembling partial JSON, routing to correct handlers, managing concurrent tool execution, and handling failures mid-tool-call are the most complex aspects of streaming implementation.</p></li><li><p><strong>GPU rendering is an outlier</strong>: Warp&#39;s Metal-based approach is fundamentally different from every other agent. It achieves rendering performance impossible with traditional terminal escape sequences but at enormous implementation cost.</p></li></ol>`,87)])])}const m=e(i,[["render",d]]);export{u as __pageData,m as default};
